llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
  auto decl = obj->decl;
  if (auto varDecl = decl->dcst<VarDecl>()) {
    if (mCurFunc == nullptr) {
      // 全局变量引用
      auto gv = static_cast<llvm::GlobalVariable*>(varDecl->any);
      return mCurIrb->CreateLoad(self(varDecl->type), gv, varDecl->name);
    } else {
      // 局部变量引用
      auto alloca = static_cast<llvm::AllocaInst*>(varDecl->any);
      return mCurIrb->CreateLoad(self(varDecl->type), alloca, varDecl->name);
    }
  }
  ABORT();
}

llvm::Value*
EmitIR::operator()(BinaryExpr* obj)
{
  auto lhs = self(obj->lhs);
  auto rhs = self(obj->rhs);
  auto& irb = *mCurIrb;

  switch (obj->op) {
    case BinaryExpr::Add:
      return irb.CreateAdd(lhs, rhs, "addtmp");
    case BinaryExpr::Sub:
      return irb.CreateSub(lhs, rhs, "subtmp");
    case BinaryExpr::Mul:
      return irb.CreateMul(lhs, rhs, "multmp");
    case BinaryExpr::Div:
      return irb.CreateSDiv(lhs, rhs, "divtmp");
    case BinaryExpr::Mod:
      return irb.CreateSRem(lhs, rhs, "modtmp");
    default:
      ABORT();
  }
}

